        globals.insert("Blob".into(), finalize_ctor(make_blob_builtin(), "Blob"));
        globals.insert("File".into(), finalize_ctor(make_file_builtin(), "File"));
        globals.insert(
            "FileReaderSync".into(),
            finalize_ctor(make_file_reader_sync_builtin(), "FileReaderSync"),
        );

        // ── File API / drag data stores (fail-closed) ───────────────────────
        // File readers, file lists, and drag data stores need host-backed bytes,
        // asynchronous read/event dispatch, object URL lifetime management, and
        // browser drag/drop stores. Expose Chromium-compatible globals for Edge
        // feature detection, but throw instead of fabricating reads, handles,
        // or object URL lifetimes. `File` and `FileReaderSync` are standalone
        // Blob-backed.
        for name in [
            "FileReader",
            "FileList",
            "DataTransfer",
            "DataTransferItem",
            "DataTransferItemList",
        ] {
            globals.insert(
                name.into(),
                finalize_ctor(make_unsupported_web_constructor(name), name),
            );
        }
        globals.insert(
            "XMLHttpRequest".into(),
            finalize_ctor(
                make_unsupported_web_constructor("XMLHttpRequest"),
                "XMLHttpRequest",
            ),
        );
        // ── Web Streams (fail-closed) ───────────────────────────────────────
        // Streams need host-integrated queues, backpressure, promises, locking,
        // and event-loop scheduling. Expose Chromium-compatible globals, but
        // throw instead of faking asynchronous stream behavior.
        for name in [
            "ReadableStream",
            "WritableStream",
            "TransformStream",
            "ReadableStreamDefaultReader",
            "ReadableStreamBYOBReader",
            "ReadableStreamDefaultController",
            "ReadableByteStreamController",
            "ReadableStreamBYOBRequest",
            "WritableStreamDefaultWriter",
            "WritableStreamDefaultController",
            "TransformStreamDefaultController",
            "ByteLengthQueuingStrategy",
            "CountQueuingStrategy",
            "TextEncoderStream",
            "TextDecoderStream",
            "CompressionStream",
            "DecompressionStream",
        ] {
            globals.insert(
                name.into(),
                finalize_ctor(make_unsupported_web_constructor(name), name),
            );
        }

        // ── Web Storage (in-memory) ─────────────────────────────────────────
        // `Storage`, `localStorage`, and `sessionStorage` expose only safe
        // standalone behavior: separate per-global in-memory key/value lists.
        // They deliberately do not model persistence, quota, origins, privacy
        // partitioning, storage events, or cross-context sharing.
        globals.insert(
            "Storage".into(),
            finalize_ctor(make_storage_builtin(), "Storage"),
        );
        globals.insert("localStorage".into(), make_storage_object());
        globals.insert("sessionStorage".into(), make_storage_object());

        // ── Storage / database / cache / cookies (fail-closed) ──────────────
        //
        // IndexedDB, the Cache API, the Cookie Store, and the Storage / quota
        // / bucket APIs are host-integrated. Real behavior requires an
        // origin, a backing key-value/blob store, durable on-disk persistence,
        // quota and bucket bookkeeping, transaction lifetimes, request/event
        // dispatch, an HTTP cache layer with `Request`/`Response` integration,
        // and a cookie jar with same-site/secure semantics. This standalone
        // engine has none of those, so expose the Chromium-style
        // constructor/prototype names that page scripts feature-detect and
        // reject every operation rather than pretending data was stored.
        // Navigator-only entry points (`navigator.storage`,
        // `navigator.cookieStore`, `navigator.storageBuckets`) remain absent
        // because the standalone engine does not preinstall `navigator`.
