    #[test]
    fn e2e_dom_exception_constructor_shape() {
        assert_eval_true("typeof DOMException === 'function'");
        assert_eval_true("DOMException.name === 'DOMException' && DOMException.length === 0");
        assert_eval_true(
            "var e = new DOMException(); e.name === 'Error' && e.message === '' && e.code === 0",
        );
        assert_eval_true(
            "var e = new DOMException('nope', 'SyntaxError'); e.name === 'SyntaxError' && e.message === 'nope' && e.code === 12",
        );
        assert_eval_true(
            "var e = new DOMException('x', 'NotAStandardName'); e.name === 'NotAStandardName' && e.code === 0",
        );
        assert_eval_true("new DOMException('x', 'AbortError') instanceof DOMException");
        assert_eval_true("new DOMException('x', 'AbortError') instanceof Error");
        assert_eval_true("Object.getPrototypeOf(DOMException.prototype) === Error.prototype");
        assert_eval_true(
            "Object.prototype.toString.call(new DOMException('x')) === '[object DOMException]'",
        );
    }

    #[test]
    fn e2e_dom_exception_properties_and_constants() {
        assert_eval_true("Object.keys(new DOMException('x', 'SyntaxError')).length === 0");
        assert_eval_true(
            "Object.getOwnPropertyDescriptor(new DOMException('x'), 'name') === undefined",
        );
        assert_eval_true(
            "var d = Object.getOwnPropertyDescriptor(DOMException.prototype, 'name'); typeof d.get === 'function' && d.set === undefined && d.enumerable === true && d.configurable === true",
        );
        assert_eval_true(
            "var d = Object.getOwnPropertyDescriptor(DOMException.prototype, 'code'); typeof d.get === 'function' && d.enumerable === true && d.configurable === true",
        );
        assert_eval_true(
            "DOMException.SYNTAX_ERR === 12 && DOMException.prototype.SYNTAX_ERR === 12 && DOMException.DATA_CLONE_ERR === 25",
        );
        assert_eval_true(
            "var d = Object.getOwnPropertyDescriptor(DOMException, 'SYNTAX_ERR'); d.value === 12 && d.writable === false && d.enumerable === true && d.configurable === false",
        );
        assert_eval_true(
            "var d = Object.getOwnPropertyDescriptor(DOMException.prototype, 'DATA_CLONE_ERR'); d.value === 25 && d.writable === false && d.enumerable === true && d.configurable === false",
        );
    }

    #[test]
    fn e2e_dom_exception_callable_behavior_and_to_string() {
        assert_eval_type_error("DOMException('x', 'SyntaxError')");
        assert_eval_true("String(new DOMException('', 'SyntaxError')) === 'SyntaxError'");
        assert_eval_true("String(new DOMException('bad', 'SyntaxError')) === 'SyntaxError: bad'");
        assert_eval_type_error("DOMException.prototype.toString.call({})");
    }

    #[test]
    fn e2e_url_constructor_real_basic() {
        assert_eval_true("typeof URL === 'function' && URL.name === 'URL'");
        assert_eval_true("typeof URL.createObjectURL === 'function'");
        assert_eval_true("typeof URL.revokeObjectURL === 'function'");
        // Object-URL helpers are host-integrated and remain fail-closed.
        assert_eval_type_error("URL.createObjectURL({})");
        assert_eval_type_error("URL.revokeObjectURL('blob:https://example.test/id')");

        // Calling without `new` still constructs (Stator's __call__ slot
        // is invoked uniformly), and invalid input throws TypeError.
        assert_eval_type_error("new URL('not a url')");
        assert_eval_type_error("new URL('http://exämple.test/')");
        assert_eval_type_error("new URL('../x')");

        // Absolute parse + component getters.
        assert_eval_true(
            "(new URL('https://u:p@a.test:8443/x/y?q=1&r=2#h')).href === 'https://u:p@a.test:8443/x/y?q=1&r=2#h'",
        );
        assert_eval_true("(new URL('https://u:p@a.test:8443/x?q=1#h')).protocol === 'https:'");
        assert_eval_true("(new URL('https://u:p@a.test:8443/x?q=1#h')).hostname === 'a.test'");
        assert_eval_true("(new URL('https://a.test:8443/x')).host === 'a.test:8443'");
        assert_eval_true("(new URL('https://a.test/x')).host === 'a.test'");
        assert_eval_true("(new URL('https://a.test:443/x')).port === ''");
        assert_eval_true("(new URL('http://a.test:80/x')).port === ''");
        assert_eval_true("(new URL('http://a.test:8080/x')).port === '8080'");
        assert_eval_true("(new URL('https://a.test/x?q=1#h')).pathname === '/x'");
        assert_eval_true("(new URL('https://a.test/x?q=1#h')).search === '?q=1'");
        assert_eval_true("(new URL('https://a.test/x?q=1#h')).hash === '#h'");
        assert_eval_true("(new URL('https://u:p@a.test/x')).username === 'u'");
        assert_eval_true("(new URL('https://u:p@a.test/x')).password === 'p'");
        assert_eval_true("(new URL('https://a.test:8443/x')).origin === 'https://a.test:8443'");

        // Default-port collapse on serialization.
        assert_eval_true("(new URL('http://a.test:80/x')).href === 'http://a.test/x'");

        // Dot-segment removal for special schemes.
        assert_eval_true("(new URL('https://a.test/x/./y/../z')).pathname === '/x/z'");

        // Relative resolution against a base.
        assert_eval_true("(new URL('../z', 'https://a.test/x/y/')).href === 'https://a.test/x/z'");
        assert_eval_true("(new URL('/abs', 'https://a.test/x/y')).href === 'https://a.test/abs'");
        assert_eval_true(
            "(new URL('#frag', 'https://a.test/p?q=1')).href === 'https://a.test/p?q=1#frag'",
        );
        // Base can be another URL instance.
        assert_eval_true(
            "(new URL('rel', new URL('https://a.test/x/'))).href === 'https://a.test/x/rel'",
        );

        // Opaque-scheme URL (mailto, data, etc.).
        assert_eval_true("(new URL('mailto:foo@bar')).protocol === 'mailto:'");
        assert_eval_true("(new URL('mailto:foo@bar')).pathname === 'foo@bar'");
        assert_eval_true("(new URL('mailto:foo@bar')).origin === 'null'");

        // IPv6 host.
        assert_eval_true("(new URL('https://[::1]:8443/x')).hostname === '[::1]'");
        assert_eval_true("(new URL('https://[::1]:8443/x')).href === 'https://[::1]:8443/x'");

        // toString / toJSON.
        assert_eval_true("(new URL('https://a.test/x')).toString() === 'https://a.test/x'");
        assert_eval_true("(new URL('https://a.test/x')).toJSON() === 'https://a.test/x'");

        // Setters.
        assert_eval_true("var u = new URL('https://a.test/x'); u.hash = 'y'; u.hash === '#y'");
        assert_eval_true(
            "var u = new URL('https://a.test/x?old=1'); u.search = 'new=2'; u.search === '?new=2'",
        );
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.pathname = '/y/./z'; u.pathname === '/y/z'",
        );
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.port = '8080'; u.host === 'a.test:8080'",
        );
        assert_eval_true(
            "var u = new URL('https://a.test:8080/x'); u.port = ''; u.host === 'a.test'",
        );
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.hostname = 'b.test'; u.hostname === 'b.test'",
        );
        // Cross-class protocol change is a no-op (spec behavior).
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.protocol = 'mailto'; u.protocol === 'https:'",
        );
        // Same-class protocol change succeeds.
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.protocol = 'http'; u.protocol === 'http:'",
        );
        // href setter re-parses.
        assert_eval_true(
            "var u = new URL('https://a.test/x'); u.href = 'http://b.test/y'; u.host === 'b.test' && u.protocol === 'http:'",
        );

        // URL.canParse / URL.parse.
        assert_eval_true("URL.canParse('https://a.test/x') === true");
        assert_eval_true("URL.canParse('not a url') === false");
        assert_eval_true("URL.canParse('rel', 'https://a.test/') === true");
        assert_eval_true("URL.parse('not a url') === null");
        assert_eval_true("URL.parse('https://a.test/x').href === 'https://a.test/x'");

        // Live `url.searchParams` is intentionally absent (host-integrated
        // identity semantics are not implemented).
        assert_eval_true("typeof (new URL('https://a.test/x?q=1')).searchParams === 'undefined'");
    }

    #[test]
    fn e2e_url_search_params_real_basic() {
        assert_eval_true(
            "typeof URLSearchParams === 'function' && URLSearchParams.name === 'URLSearchParams'",
        );

        // Construction.
        assert_eval_true("new URLSearchParams().toString() === ''");
        assert_eval_true("new URLSearchParams('a=1&b=2').toString() === 'a=1&b=2'");
        assert_eval_true("new URLSearchParams('?a=1&b=2').toString() === 'a=1&b=2'");
        assert_eval_true("new URLSearchParams([['a','1'],['b','2']]).toString() === 'a=1&b=2'");
        assert_eval_true("new URLSearchParams({a:'1', b:'2'}).toString() === 'a=1&b=2'");

        // Encoding: space -> '+', reserved chars percent-encoded.
        assert_eval_true("new URLSearchParams([['a b','1+2']]).toString() === 'a+b=1%2B2'");

        // get / getAll / has / size.
        assert_eval_true("(new URLSearchParams('a=1&a=2&b=3')).get('a') === '1'");
        assert_eval_true(
            "JSON.stringify((new URLSearchParams('a=1&a=2&b=3')).getAll('a')) === '[\"1\",\"2\"]'",
        );
        assert_eval_true("(new URLSearchParams('a=1&b=2')).has('a') === true");
        assert_eval_true("(new URLSearchParams('a=1&b=2')).has('c') === false");
        assert_eval_true("(new URLSearchParams('a=1&b=2&a=3')).size === 3");
        // has(name, value) for the two-arg form.
        assert_eval_true("(new URLSearchParams('a=1&a=2')).has('a','2') === true");
        assert_eval_true("(new URLSearchParams('a=1&a=2')).has('a','9') === false");

        // append / set / delete.
        assert_eval_true(
            "var p = new URLSearchParams('a=1'); p.append('a','2'); p.toString() === 'a=1&a=2'",
        );
        assert_eval_true(
            "var p = new URLSearchParams('a=1&a=2&b=3'); p.set('a','9'); p.toString() === 'a=9&b=3'",
        );
        assert_eval_true(
            "var p = new URLSearchParams('a=1&b=2&a=3'); p.delete('a'); p.toString() === 'b=2'",
        );
        // delete(name, value) two-arg.
        assert_eval_true(
            "var p = new URLSearchParams('a=1&a=2&a=3'); p.delete('a','2'); p.toString() === 'a=1&a=3'",
        );

        // sort (stable by name).
        assert_eval_true(
            "var p = new URLSearchParams('c=1&a=2&b=3&a=4'); p.sort(); p.toString() === 'a=2&a=4&b=3&c=1'",
        );

        // get returns null for missing.
        assert_eval_true("(new URLSearchParams('a=1')).get('z') === null");
    }

    #[test]
    fn e2e_url_search_params_copies_from_other_instance() {
        // Constructing from another URLSearchParams copies its pair list,
        // including duplicates and order. The copy must be independent of
        // the source after construction.
        assert_eval_true(
            "var a = new URLSearchParams('a=1&a=2&b=3'); \
             var b = new URLSearchParams(a); \
             b.toString() === 'a=1&a=2&b=3' && b.size === 3",
        );
        assert_eval_true(
            "var a = new URLSearchParams('x=1'); \
             var b = new URLSearchParams(a); \
             a.append('x','2'); \
             b.toString() === 'x=1' && a.toString() === 'x=1&x=2'",
        );
        // Empty source yields empty target.
        assert_eval_true("new URLSearchParams(new URLSearchParams()).toString() === ''");
        // Percent-encoded values survive the copy.
        assert_eval_true(
            "var a = new URLSearchParams([['a b','1+2']]); \
             new URLSearchParams(a).toString() === 'a+b=1%2B2'",
        );
    }

    #[test]
    fn e2e_url_object_url_helpers_remain_fail_closed() {
        // Regression: object URL lifetime is host-owned, so these stay
        // fail-closed even though their function objects exist.
        assert_eval_true("typeof URL.createObjectURL === 'function'");
        assert_eval_true("typeof URL.revokeObjectURL === 'function'");
        assert_eval_type_error("URL.createObjectURL({})");
        assert_eval_type_error("URL.revokeObjectURL('blob:https://example.test/id')");
    }

    #[test]
    fn e2e_url_branded_methods_reject_foreign_receiver() {
        // Brand check on prototype methods.
        assert_eval_type_error("URL.prototype.toString.call({})");
        assert_eval_type_error("URLSearchParams.prototype.append.call({}, 'a', 'b')");
        // Branded receivers via .call work.
        assert_eval_true(
            "URL.prototype.toString.call(new URL('https://a.test/')) === 'https://a.test/'",
        );
    }

    #[test]
    fn e2e_headers_constructor_shape() {
        assert_eval_true("typeof Headers === 'function' && Headers.name === 'Headers'");
        assert_eval_true("new Headers() instanceof Headers");
        assert_eval_true("new Headers(undefined) instanceof Headers");
        assert_eval_true("new Headers(null) instanceof Headers");
        assert_eval_true("Object.prototype.toString.call(new Headers()) === '[object Headers]'");
    }

    #[test]
    fn e2e_headers_construct_from_record() {
        assert_eval_true(
            "(new Headers({ 'Content-Type': 'text/plain', 'X-Foo': 'bar' })).get('content-type') === 'text/plain'",
        );
        assert_eval_true("(new Headers({ 'X-Foo': 'bar' })).get('X-FOO') === 'bar'");
        assert_eval_true("(new Headers({ a: 'x' })).has('A') === true");
    }

    #[test]
    fn e2e_headers_construct_from_sequence() {
        assert_eval_true("(new Headers([['X-A','1'],['X-A','2']])).get('x-a') === '1, 2'");
        assert_eval_true(
            "(new Headers([['Set-Cookie','a=1'],['Set-Cookie','b=2']])).getSetCookie().length === 2",
        );
        assert_eval_type_error("new Headers([['only-one']])");
        assert_eval_type_error("new Headers(['not-a-pair'])");
    }

    #[test]
    fn e2e_headers_copy_from_another_headers() {
        assert_eval_true(
            "var h1 = new Headers({ 'X-A': '1' }); h1.append('X-A','2'); var h2 = new Headers(h1); h2.get('x-a') === '1, 2'",
        );
        assert_eval_true(
            "var h1 = new Headers(); h1.append('Set-Cookie','a=1'); h1.append('Set-Cookie','b=2'); var h2 = new Headers(h1); h2.getSetCookie().length === 2",
        );
    }

    #[test]
    fn e2e_headers_append_set_delete_get_has() {
        assert_eval_true(
            "var h = new Headers(); h.append('A','1'); h.append('a','2'); h.get('a') === '1, 2'",
        );
        assert_eval_true(
            "var h = new Headers(); h.append('a','1'); h.append('b','2'); h.append('a','3'); h.set('A','X'); h.get('a') === 'X' && h.get('b') === '2'",
        );
        assert_eval_true(
            "var h = new Headers({ a:'1', b:'2' }); h.delete('A'); h.has('a') === false && h.has('b') === true",
        );
        assert_eval_true("(new Headers()).get('missing') === null");
        assert_eval_true("(new Headers()).has('missing') === false");
    }

    #[test]
    fn e2e_headers_value_normalization_trims_http_whitespace() {
        assert_eval_true("(new Headers({ a: '  hello  ' })).get('a') === 'hello'");
        assert_eval_true(
            "var h = new Headers(); h.append('a', '\\t value \\t'); h.get('a') === 'value'",
        );
    }

    #[test]
    fn e2e_headers_invalid_name_throws() {
        assert_eval_type_error("new Headers({ '': 'x' })");
        assert_eval_type_error("new Headers({ 'a b': 'x' })");
        assert_eval_type_error("new Headers({ 'a:b': 'x' })");
        assert_eval_type_error("(new Headers()).append('a b', 'x')");
        assert_eval_type_error("(new Headers()).set('a:b', 'x')");
        assert_eval_type_error("(new Headers()).get('a b')");
        assert_eval_type_error("(new Headers()).has('a b')");
        assert_eval_type_error("(new Headers()).delete('a b')");
    }

    #[test]
    fn e2e_headers_invalid_value_throws() {
        assert_eval_type_error("(new Headers()).append('a', 'bad\\0value')");
        assert_eval_type_error("(new Headers()).append('a', 'bad\\nvalue')");
        assert_eval_type_error("(new Headers()).append('a', 'bad\\rvalue')");
        assert_eval_type_error("(new Headers()).set('a', 'bad\\0')");
    }

    #[test]
    fn e2e_headers_iteration_sort_and_combine() {
        // Iteration order is by sorted lowercase name; duplicates merged
        // except for Set-Cookie which stays as separate entries.
        assert_eval_true(
            "var h = new Headers(); h.append('X-B','2'); h.append('X-A','1'); h.append('X-A','3'); var out = []; for (var e of h) out.push(e[0]+'='+e[1]); out.join('|') === 'x-a=1, 3|x-b=2'",
        );
        assert_eval_true(
            "var h = new Headers(); h.append('Set-Cookie','a=1'); h.append('X-A','v'); h.append('Set-Cookie','b=2'); var out = []; for (var e of h.entries()) out.push(e[0]+'='+e[1]); out.join('|') === 'set-cookie=a=1|set-cookie=b=2|x-a=v'",
        );
        assert_eval_true(
            "var h = new Headers({ z:'1', a:'2', m:'3' }); var keys = []; for (var k of h.keys()) keys.push(k); keys.join(',') === 'a,m,z'",
        );
        assert_eval_true(
            "var h = new Headers({ z:'1', a:'2' }); var vals = []; for (var v of h.values()) vals.push(v); vals.join(',') === '2,1'",
        );
    }

    #[test]
    fn e2e_headers_for_each_signature() {
        assert_eval_true(
            "var h = new Headers({ a:'1', b:'2' }); var calls = []; h.forEach(function(v,k,o){ calls.push(k+'='+v+'/'+(o===h)); }); calls.join('|') === 'a=1/true|b=2/true'",
        );
        assert_eval_true(
            "var h = new Headers({ a:'1' }); var tag; h.forEach(function(){ tag = this.x; }, { x: 'thisArg' }); tag === 'thisArg'",
        );
    }

    #[test]
    fn e2e_headers_get_set_cookie() {
        assert_eval_true("Array.isArray((new Headers()).getSetCookie())");
        assert_eval_true("(new Headers()).getSetCookie().length === 0");
        assert_eval_true(
            "var h = new Headers(); h.append('Set-Cookie','a=1'); h.append('set-cookie','b=2'); var r = h.getSetCookie(); r.length === 2 && r[0] === 'a=1' && r[1] === 'b=2'",
        );
        // get() still joins all Set-Cookie values with ", " per spec.
        assert_eval_true(
            "var h = new Headers(); h.append('Set-Cookie','a=1'); h.append('Set-Cookie','b=2'); h.get('set-cookie') === 'a=1, b=2'",
        );
    }

    #[test]
    fn e2e_headers_branded_methods_reject_foreign_receiver() {
        assert_eval_type_error("Headers.prototype.append.call({}, 'a', 'b')");
        assert_eval_type_error("Headers.prototype.get.call({}, 'a')");
        assert_eval_type_error("Headers.prototype.set.call(new Map(), 'a', 'b')");
        // Branded receivers via .call work.
        assert_eval_true(
            "var h = new Headers(); Headers.prototype.append.call(h,'X','1'); h.get('x') === '1'",
        );
    }

    #[test]
    fn e2e_headers_does_not_unlock_fetch() {
        // Real Headers must not regress fail-closed fetch. Request/Response are
        // standalone in-memory wrappers only.
        assert_eval_true("typeof fetch === 'function'");
        assert_eval_type_error("fetch('https://example.test/')");
        assert_eval_type_error("new Request('/api')");
        // Even when given a real Headers object as part of init.
        assert_eval_type_error(
            "fetch('https://example.test/', { headers: new Headers({ 'X-A': '1' }) })",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/api', { headers: new Headers({ 'X-A': '1' }) }); q.headers.get('x-a') === '1'",
        );
        // Response accepts a real Headers init and copies values.
        assert_eval_true(
            "var r = new Response('ok', { headers: new Headers({ 'X-A': '1' }) }); r.headers.get('x-a') === '1'",
        );
    }

    #[test]
    fn e2e_form_data_constructor_shape() {
        assert_eval_true("typeof FormData === 'function' && FormData.name === 'FormData'");
        assert_eval_true("new FormData() instanceof FormData");
        assert_eval_true("new FormData(undefined) instanceof FormData");
        assert_eval_true("Object.prototype.toString.call(new FormData()) === '[object FormData]'");
        assert_eval_type_error("new FormData(null)");
        assert_eval_type_error("new FormData({})");
    }

    #[test]
    fn e2e_form_data_append_get_get_all_has_delete() {
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.append('a','2'); f.get('a') === '1'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.append('a','2'); var all = f.getAll('a'); all.length === 2 && all[0] === '1' && all[1] === '2'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.append('b','2'); f.has('a') && f.has('b') && !f.has('c')",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.append('a','2'); f.append('b','3'); f.delete('a'); !f.has('a') && f.get('a') === null && f.get('b') === '3'",
        );
    }

    #[test]
    fn e2e_form_data_set_replaces_duplicates_in_place() {
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.append('b','2'); f.append('a','3'); f.set('a','X'); var out = []; for (var e of f) out.push(e[0]+'='+e[1]); out.join('|') === 'a=X|b=2'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a','1'); f.set('b','2'); var out = []; for (var e of f.entries()) out.push(e[0]+'='+e[1]); out.join('|') === 'a=1|b=2'",
        );
    }

    #[test]
    fn e2e_form_data_iteration_and_for_each_order() {
        assert_eval_true(
            "var f = new FormData(); f.append('b','2'); f.append('a','1'); f.append('a','3'); var out = []; for (var e of f.entries()) out.push(e[0]+'='+e[1]); out.join('|') === 'b=2|a=1|a=3'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('b','2'); f.append('a','1'); var keys = []; for (var k of f.keys()) keys.push(k); keys.join(',') === 'b,a'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('b','2'); f.append('a','1'); var vals = []; for (var v of f.values()) vals.push(v); vals.join(',') === '2,1'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('x','1'); var seen = []; f.forEach(function(v,k,o){ seen.push(this.tag+':'+k+'='+v+':'+(o===f)); }, { tag: 'T' }); seen.join('|') === 'T:x=1:true'",
        );
    }

    #[test]
    fn e2e_form_data_string_coercion() {
        assert_eval_true(
            "var f = new FormData(); f.append(123, true); f.append(null, undefined); f.get('123') === 'true' && f.get('null') === 'undefined'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append({ toString: function(){ return 'name'; } }, { toString: function(){ return 'value'; } }); f.get('name') === 'value'",
        );
        assert_eval_type_error("(new FormData()).append(Symbol('s'), 'x')");
        assert_eval_type_error("(new FormData()).append('a', Symbol('s'))");
    }

    #[test]
    fn e2e_form_data_blob_value_wraps_into_file_named_blob() {
        assert_eval_true(
            "var f = new FormData(); f.append('b', new Blob(['hello'], { type: 'text/plain' })); var v = f.get('b'); v instanceof File && v instanceof Blob && v.name === 'blob' && v.size === 5 && v.type === 'text/plain'",
        );
    }

    #[test]
    fn e2e_form_data_blob_value_with_filename_uses_provided_name() {
        assert_eval_true(
            "var f = new FormData(); f.append('b', new Blob(['hi']), 'note.txt'); var v = f.get('b'); v instanceof File && v.name === 'note.txt' && v.size === 2",
        );
    }

    #[test]
    fn e2e_form_data_file_value_preserves_identity_and_name() {
        assert_eval_true(
            "var f = new FormData(); var file = new File(['body'], 'body.txt'); f.append('f', file); var v = f.get('f'); v === file && v.name === 'body.txt'",
        );
    }

    #[test]
    fn e2e_form_data_file_value_with_filename_override_creates_new_file() {
        assert_eval_true(
            "var f = new FormData(); var file = new File(['body'], 'body.txt', { type: 'text/plain', lastModified: 12345 }); f.append('f', file, 'override.txt'); var v = f.get('f'); v !== file && v instanceof File && v.name === 'override.txt' && v.size === 4 && v.type === 'text/plain' && v.lastModified === 12345",
        );
    }

    #[test]
    fn e2e_form_data_set_blob_replaces_in_place_with_file_entry() {
        assert_eval_true(
            "var f = new FormData(); f.append('x','1'); f.append('a', new Blob(['old'])); f.append('a', 'b'); f.set('a', new Blob(['new']), 'new.bin'); var all = f.getAll('a'); all.length === 1 && all[0] instanceof File && all[0].name === 'new.bin' && all[0].size === 3",
        );
    }

    #[test]
    fn e2e_form_data_blob_entries_iterate_as_file_objects() {
        assert_eval_true(
            "var f = new FormData(); f.append('a', new Blob(['x'])); f.append('b', 'plain'); var seen = []; for (var e of f) seen.push(e[0] + ':' + (e[1] instanceof File ? 'F' : typeof e[1])); seen.join('|') === 'a:F|b:string'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a', new Blob(['x'])); var vs = []; for (var v of f.values()) vs.push(v instanceof File); vs.length === 1 && vs[0] === true",
        );
    }

    #[test]
    fn e2e_form_data_blob_for_each_passes_file_value() {
        assert_eval_true(
            "var f = new FormData(); f.append('a', new Blob(['x']), 'a.txt'); var seen; f.forEach(function(v,k,o){ seen = (v instanceof File) && v.name === 'a.txt' && k === 'a' && o === f; }); seen === true",
        );
    }

    #[test]
    fn e2e_form_data_filename_is_ignored_for_string_values() {
        // Per WebIDL overload resolution: filename only applies to the Blob
        // overload. With a string value, the third argument is ignored.
        assert_eval_true(
            "var f = new FormData(); f.append('a', 'b', 'file.txt'); f.get('a') === 'b'",
        );
        assert_eval_true("var f = new FormData(); f.set('a', 'b', 'file.txt'); f.get('a') === 'b'");
    }

    #[test]
    fn e2e_form_data_non_branded_blob_prototype_is_stringified() {
        // A plain object whose prototype chain reaches Blob.prototype is NOT a
        // real Blob (no internal brand) and per WebIDL is treated as a string.
        assert_eval_true(
            "var f = new FormData(); f.append('a', Object.create(Blob.prototype)); typeof f.get('a') === 'string'",
        );
        assert_eval_true(
            "var f = new FormData(); f.append('a', Blob.prototype); typeof f.get('a') === 'string'",
        );
    }

    #[test]
    fn e2e_form_data_rejects_symbol_in_blob_path() {
        // Symbol filename still throws via ToString coercion.
        assert_eval_type_error("(new FormData()).append('a', new Blob(['x']), Symbol('s'))");
    }

    #[test]
    fn e2e_form_data_does_not_unlock_fetch_or_request_response() {
        assert_eval_type_error("fetch('https://example.test/', { body: new FormData() })");
        assert_eval_type_error(
            "new Request('https://example.test/api', { method: 'POST', body: new FormData() })",
        );
        // FormData bodies are explicitly rejected by the standalone Response
        // because no real multipart serializer exists in this engine.
        assert_eval_type_error("new Response(new FormData())");
        // Even with Blob/File entries populated, FormData bodies still fail
        // closed — no multipart serialization is implemented.
        assert_eval_type_error(
            "var f = new FormData(); f.append('a', new Blob(['x'])); new Response(f)",
        );
        assert_eval_type_error(
            "var f = new FormData(); f.append('a', new File(['x'], 'x.txt')); new Request('https://example.test/', { method: 'POST', body: f })",
        );
    }

    #[test]
    fn e2e_blob_construction_empty_and_string_parts() {
        assert_eval_true("typeof Blob === 'function' && Blob.name === 'Blob'");
        assert_eval_true("var b = new Blob(); b.size === 0 && b.type === ''");
        assert_eval_true("var b = new Blob([]); b.size === 0 && b.type === ''");
        assert_eval_true("var b = new Blob(['hello']); b.size === 5 && b.type === ''");
        assert_eval_true(
            "var b = new Blob(['he', 'llo', ' world']); b.size === 11 && b.type === ''",
        );
        // UTF-8 byte length, not code-unit length.
        assert_eval_true("var b = new Blob(['caf\u{00e9}']); b.size === 5");
        // Non-string primitives are coerced via ToString per spec.
        assert_eval_true(
            "var b = new Blob([123, true, null]); b.size === ('123' + 'true' + 'null').length",
        );
    }

    #[test]
    fn e2e_blob_type_normalization() {
        assert_eval_true(
            "var b = new Blob(['x'], { type: 'TEXT/Plain' }); b.type === 'text/plain'",
        );
        assert_eval_true("var b = new Blob(['x'], { type: '' }); b.type === ''");
        // Non-ASCII-printable characters reset the type to "".
        assert_eval_true("var b = new Blob(['x'], { type: 'tex\u{00e9}/plain' }); b.type === ''");
        assert_eval_true("var b = new Blob(['x']); b.type === ''");
        assert_eval_true("var b = new Blob(['x'], null); b.type === ''");
        assert_eval_true("var b = new Blob(['x'], undefined); b.type === ''");
    }

    #[test]
    fn e2e_blob_slice_semantics_and_immutability() {
        assert_eval_true(
            "var b = new Blob(['hello world']); var s = b.slice(0, 5); s.size === 5 && b.size === 11",
        );
        assert_eval_true("var b = new Blob(['hello world']); var s = b.slice(-5); s.size === 5");
        assert_eval_true(
            "var b = new Blob(['hello world']); var s = b.slice(6, 100); s.size === 5",
        );
        assert_eval_true("var b = new Blob(['hello world']); var s = b.slice(8, 2); s.size === 0");
        assert_eval_true(
            "var b = new Blob(['x'], { type: 'text/plain' }); var s = b.slice(0, 1, 'TEXT/HTML'); s.type === 'text/html' && b.type === 'text/plain'",
        );
        assert_eval_true(
            "var b = new Blob(['x']); b.size = 99; b.type = 'evil'; b.size === 1 && b.type === ''",
        );
    }

    #[test]
    fn e2e_blob_construction_from_arraybuffer_and_typed_array_and_blob() {
        assert_eval_true(
            "var u = new Uint8Array([104, 105]); var b = new Blob([u, ' there']); b.size === 8",
        );
        assert_eval_true(
            "var ab = new ArrayBuffer(4); var v = new Uint8Array(ab); v[0]=65;v[1]=66;v[2]=67;v[3]=68; var b = new Blob([ab]); b.size === 4",
        );
        assert_eval_true(
            "var inner = new Blob(['abc']); var outer = new Blob([inner, 'de']); outer.size === 5",
        );
        assert_eval_true(
            "var ab = new ArrayBuffer(8); var dv = new DataView(ab, 2, 4); var b = new Blob([dv]); b.size === 4",
        );
    }

    #[test]
    fn e2e_blob_rejects_unsupported_part_types() {
        assert_eval_type_error("new Blob([{}])");
        assert_eval_type_error("new Blob([[1, 2, 3]])");
        assert_eval_type_error("new Blob('not-iterable-as-parts-bag'.length ? 5 : 5)");
        assert_eval_type_error("new Blob(['x'], 'not-an-object')");
        assert_eval_type_error("new Blob(['x'], 42)");
    }

    #[test]
    fn e2e_blob_text_and_array_buffer_return_promises() {
        assert_eval_true(
            "var b = new Blob(['hello']); var t = b.text(); typeof t === 'object' && typeof t.then === 'function'",
        );
        assert_eval_true(
            "var b = new Blob(['hello']); var p = b.arrayBuffer(); typeof p === 'object' && typeof p.then === 'function'",
        );
        // Decoded contents propagate via .then() once microtasks drain.
        assert_eval_true_after_microtasks(
            "var blobTextSeen = ''; (new Blob(['hi'])).text().then(function(v){ blobTextSeen = v; });",
            "blobTextSeen === 'hi'",
        );
    }

    #[test]
    fn e2e_blob_stream_and_bytes_remain_fail_closed() {
        assert_eval_true("typeof Blob.prototype.stream === 'function'");
        assert_eval_true("typeof Blob.prototype.bytes === 'function'");
        assert_eval_type_error("(new Blob(['x'])).stream()");
        assert_eval_type_error("(new Blob(['x'])).bytes()");
    }

    #[test]
    fn e2e_blob_does_not_unlock_fetch_or_object_url() {
        // Even with a real Blob value, fetch/objectURL remain fail-closed: no
        // fake network/file/URL lifetime. Real Request/Response accept Blob
        // bodies and snapshot bytes into memory.
        assert_eval_type_error("fetch('https://example.test/', { body: new Blob(['x']) })");
        assert_eval_true(
            "var q = new Request('https://example.test/api', { method: 'POST', body: new Blob(['x']) }); q.headers.get('content-type') === null",
        );
        assert_eval_true(
            "var r = new Response(new Blob(['x'], { type: 'text/plain' })); r.headers.get('content-type') === 'text/plain'",
        );
        assert_eval_type_error("URL.createObjectURL(new Blob(['x']))");
    }

    #[test]
    fn e2e_file_construction_properties_and_prototype_chain() {
        assert_eval_true("typeof File === 'function' && File.name === 'File'");
        assert_eval_true(
            "var f = new File(['hello'], 'greeting.txt', { type: 'TEXT/Plain', lastModified: 1234 }); f instanceof File && f instanceof Blob",
        );
        assert_eval_true(
            "var f = new File(['hello'], 'greeting.txt', { type: 'TEXT/Plain', lastModified: 1234 }); f.name === 'greeting.txt' && f.lastModified === 1234 && f.type === 'text/plain' && f.size === 5",
        );
        assert_eval_true(
            "var f = new File([], 'x'); typeof f.lastModified === 'number' && f.lastModified >= 0",
        );
        assert_eval_true("var f = new File([], 'dir/name\\\\leaf'); f.name === 'dir/name\\\\leaf'");
        assert_eval_true(
            "var f = new File([], 'x'); f.webkitRelativePath === '' && Object.prototype.toString.call(f) === '[object File]'",
        );
    }

    #[test]
    fn e2e_file_blob_compatible_parts_and_immutability() {
        assert_eval_true(
            "var u = new Uint8Array([65, 66]); var f = new File([u, 'C'], 'abc.bin'); f.size === 3",
        );
        assert_eval_true(
            "var ab = new ArrayBuffer(4); var v = new Uint8Array(ab); v[0]=1;v[1]=2;v[2]=3;v[3]=4; var f = new File([ab], 'bytes.bin'); v[0]=9; f.size === 4",
        );
        assert_eval_true(
            "var b = new Blob(['abc']); var f = new File([b, 'de'], 'abcde.txt'); f.size === 5",
        );
        assert_eval_true(
            "var f1 = new File(['abc'], 'a.txt'); var f2 = new File([f1, 'd'], 'b.txt'); f2.size === 4",
        );
        assert_eval_true(
            "var ab = new ArrayBuffer(8); var dv = new DataView(ab, 2, 4); var f = new File([dv], 'view.bin'); f.size === 4",
        );
        assert_eval_true(
            "var f = new File(['x'], 'x.txt'); f.name = 'evil'; f.lastModified = 9; f.name === 'x.txt' && f.lastModified !== 9",
        );
    }

    #[test]
    fn e2e_file_type_normalization_slice_text_and_array_buffer() {
        assert_eval_true(
            "var f = new File(['x'], 'x.txt', { type: 'TEXT/HTML' }); f.type === 'text/html'",
        );
        assert_eval_true(
            "var f = new File(['x'], 'x.txt', { type: 'tex\u{00e9}/plain' }); f.type === ''",
        );
        assert_eval_true(
            "var f = new File(['hello world'], 'h.txt', { type: 'text/plain' }); var s = f.slice(6, 11, 'TEXT/Plain'); s instanceof Blob && !(s instanceof File) && s.size === 5 && s.type === 'text/plain'",
        );
        assert_eval_true(
            "var f = new File(['hi'], 'h.txt'); var seen = ''; f.text().then(function(v){ seen = v; }); Promise.resolve().then(function(){}); seen === 'hi' || seen === ''",
        );
        assert_eval_true(
            "var f = new File(['hi'], 'h.txt'); var p = f.arrayBuffer(); typeof p === 'object' && typeof p.then === 'function'",
        );
    }

    #[test]
    fn e2e_file_rejects_unsupported_paths_and_remains_fail_closed() {
        assert_eval_type_error("new File([{}], 'x.txt')");
        assert_eval_type_error("new File([[1, 2, 3]], 'x.txt')");
        assert_eval_type_error("new File(5, 'x.txt')");
        assert_eval_type_error("new File(['x'])");
        assert_eval_type_error("new File(['x'], 'x.txt', 42)");
        assert_eval_type_error("(new File(['x'], 'x.txt')).stream()");
        assert_eval_type_error("(new File(['x'], 'x.txt')).bytes()");
        assert_eval_type_error(
            "fetch('https://example.test/', { body: new File(['x'], 'x.txt') })",
        );
        assert_eval_true(
            "new Request('https://example.test/api', { method: 'POST', body: new File(['x'], 'x.txt') }) instanceof Request",
        );
        // File bodies are accepted by standalone Request/Response.
        assert_eval_true(
            "var r = new Response(new File(['x'], 'x.txt', { type: 'text/plain' })); r.headers.get('content-type') === 'text/plain'",
        );
        assert_eval_type_error("URL.createObjectURL(new File(['x'], 'x.txt'))");
    }

    #[test]
    fn e2e_file_and_blob_data_apis_do_not_expose_filesystem_handles() {
        // File/Blob are real in-memory data containers only. Path-like names
        // remain opaque names and do not unlock host filesystem handles.
        assert_eval_true(
            "var f = new File(['x'], 'C:\\\\Users\\\\alice\\\\secret.txt'); \
             f.name === 'C:\\\\Users\\\\alice\\\\secret.txt' && f.webkitRelativePath === ''",
        );
        for expr in [
            "typeof Blob.prototype.getFile === 'undefined'",
            "typeof Blob.prototype.getAsFileSystemHandle === 'undefined'",
            "typeof File.prototype.getFile === 'undefined'",
            "typeof File.prototype.getAsFileSystemHandle === 'undefined'",
            "typeof File.prototype.createWritable === 'undefined'",
            "typeof File.prototype.queryPermission === 'undefined'",
            "typeof File.prototype.requestPermission === 'undefined'",
        ] {
            assert_eval_true(expr);
        }
    }

    #[test]
    fn e2e_file_reader_sync_constructor_and_brand_checks() {
        assert_eval_true(
            "typeof FileReaderSync === 'function' && FileReaderSync.name === 'FileReaderSync'",
        );
        assert_eval_true("new FileReaderSync() instanceof FileReaderSync");
        assert_eval_true(
            "Object.prototype.toString.call(new FileReaderSync()) === '[object FileReaderSync]'",
        );
        // Methods exist on the prototype only (not own properties).
        assert_eval_true("typeof FileReaderSync.prototype.readAsText === 'function'");
        assert_eval_true("typeof FileReaderSync.prototype.readAsArrayBuffer === 'function'");
        assert_eval_true("typeof FileReaderSync.prototype.readAsDataURL === 'function'");
        assert_eval_true("typeof FileReaderSync.prototype.readAsBinaryString === 'function'");
        // Brand check: calling a method on the bare prototype or an unrelated
        // object must throw, not silently produce a fake read.
        assert_eval_type_error("FileReaderSync.prototype.readAsText(new Blob(['x']))");
        assert_eval_type_error("FileReaderSync.prototype.readAsArrayBuffer(new Blob(['x']))");
        assert_eval_type_error("FileReaderSync.prototype.readAsDataURL(new Blob(['x']))");
        assert_eval_type_error("FileReaderSync.prototype.readAsBinaryString(new Blob(['x']))");
        assert_eval_type_error("FileReaderSync.prototype.readAsText.call({}, new Blob(['x']))");
        // Argument must be a real Blob/File.
        assert_eval_type_error("(new FileReaderSync()).readAsText()");
        assert_eval_type_error("(new FileReaderSync()).readAsText({})");
        assert_eval_type_error("(new FileReaderSync()).readAsText(Blob.prototype)");
        assert_eval_type_error("(new FileReaderSync()).readAsArrayBuffer('not a blob')");
    }

    #[test]
    fn e2e_file_reader_sync_read_as_text() {
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new Blob(['hello'])) === 'hello'",
        );
        // UTF-8 decoding by default.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new Blob(['caf\u{00e9}'])) === 'caf\u{00e9}'",
        );
        // File extends Blob so it works too.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new File(['hi'], 'h.txt')) === 'hi'",
        );
        // Slice of a Blob.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText((new Blob(['hello world'])).slice(6, 11)) === 'world'",
        );
        // Empty Blob => empty string.
        assert_eval_true("var r = new FileReaderSync(); r.readAsText(new Blob([])) === ''");
        // Explicit UTF-8 label is accepted.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new Blob(['hi']), 'utf-8') === 'hi'",
        );
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new Blob(['hi']), 'UTF-8') === 'hi'",
        );
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsText(new Blob(['hi']), undefined) === 'hi'",
        );
        // Invalid UTF-8 bytes are replaced (lossy decode), not silently faked.
        assert_eval_true(
            "var r = new FileReaderSync(); var bad = new Uint8Array([0xff, 0xfe, 0x41]); r.readAsText(new Blob([bad])).indexOf('A') !== -1",
        );
    }

    #[test]
    fn e2e_file_reader_sync_rejects_unsupported_encodings() {
        // Anything other than UTF-8 is rejected rather than silently treated
        // as UTF-8, so callers aren't lied to about a successful decode.
        assert_eval_type_error("(new FileReaderSync()).readAsText(new Blob(['x']), 'iso-8859-1')");
        assert_eval_type_error("(new FileReaderSync()).readAsText(new Blob(['x']), 'latin1')");
        assert_eval_type_error(
            "(new FileReaderSync()).readAsText(new Blob(['x']), 'windows-1252')",
        );
        assert_eval_type_error("(new FileReaderSync()).readAsText(new Blob(['x']), 'utf-16')");
        assert_eval_type_error("(new FileReaderSync()).readAsText(new Blob(['x']), 'shift_jis')");
    }

    #[test]
    fn e2e_file_reader_sync_read_as_array_buffer() {
        assert_eval_true(
            "var r = new FileReaderSync(); var ab = r.readAsArrayBuffer(new Blob(['abc'])); ab instanceof ArrayBuffer && ab.byteLength === 3",
        );
        assert_eval_true(
            "var r = new FileReaderSync(); var ab = r.readAsArrayBuffer(new Blob(['abc'])); var v = new Uint8Array(ab); v[0]===97 && v[1]===98 && v[2]===99",
        );
        // Fresh buffer each call — mutating one does not affect the other.
        assert_eval_true(
            "var r = new FileReaderSync(); var b = new Blob(['abc']); var a1 = r.readAsArrayBuffer(b); var a2 = r.readAsArrayBuffer(b); new Uint8Array(a1)[0] = 0; new Uint8Array(a2)[0] === 97",
        );
        // Mutating the result does not retroactively alter the Blob.
        assert_eval_true(
            "var r = new FileReaderSync(); var b = new Blob(['abc']); var ab = r.readAsArrayBuffer(b); new Uint8Array(ab)[0] = 0; r.readAsText(b) === 'abc'",
        );
        // Empty Blob => zero-length buffer.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsArrayBuffer(new Blob([])).byteLength === 0",
        );
    }

    #[test]
    fn e2e_file_reader_sync_read_as_data_url() {
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsDataURL(new Blob(['Man'])) === 'data:;base64,TWFu'",
        );
        // MIME type from the Blob is preserved verbatim.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsDataURL(new Blob(['Man'], { type: 'text/plain' })) === 'data:text/plain;base64,TWFu'",
        );
        // Empty type yields the bare `data:;base64,` prefix.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsDataURL(new Blob([])) === 'data:;base64,'",
        );
        // Standard base64 padding for non-multiple-of-3 lengths.
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsDataURL(new Blob(['M'])) === 'data:;base64,TQ=='",
        );
        assert_eval_true(
            "var r = new FileReaderSync(); r.readAsDataURL(new Blob(['Ma'])) === 'data:;base64,TWE='",
        );
        // Round-trip through atob agrees with the raw bytes.
        assert_eval_true(
            "var r = new FileReaderSync(); var u = r.readAsDataURL(new Blob(['hello'])); atob(u.slice(u.indexOf(',')+1)) === 'hello'",
        );
    }

    #[test]
    fn e2e_file_reader_sync_read_as_binary_string() {
        // Each byte becomes a single UTF-16 code unit.
        assert_eval_true(
            "var r = new FileReaderSync(); var u = new Uint8Array([0,1,127,128,255]); var s = r.readAsBinaryString(new Blob([u])); s.length === 5 && s.charCodeAt(0)===0 && s.charCodeAt(1)===1 && s.charCodeAt(2)===127 && s.charCodeAt(3)===128 && s.charCodeAt(4)===255",
        );
        // ASCII bytes survive untouched.
        assert_eval_true(
            "var r = new FileReaderSync(); var s = r.readAsBinaryString(new Blob(['abc'])); s === 'abc' && s.length === 3",
        );
        // Empty Blob => empty string.
        assert_eval_true("var r = new FileReaderSync(); r.readAsBinaryString(new Blob([])) === ''");
        // UTF-8 multi-byte input is exposed byte-for-byte, not as code points.
        assert_eval_true(
            "var r = new FileReaderSync(); var s = r.readAsBinaryString(new Blob(['caf\u{00e9}'])); s.length === 5 && s.charCodeAt(3) === 0xc3 && s.charCodeAt(4) === 0xa9",
        );
    }

    #[test]
    fn e2e_file_reader_sync_does_not_unlock_async_or_object_url_paths() {
        // FileReader (async event API) must remain fail-closed.
        assert_eval_type_error("new FileReader()");
        assert_eval_type_error("FileReader()");
        // Object URL minting from a Blob/File remains fail-closed.
        assert_eval_type_error("URL.createObjectURL(new Blob(['x']))");
        assert_eval_type_error("URL.createObjectURL(new File(['x'], 'x.txt'))");
        // fetch remains fail-closed. Real Request/Response accept Blob/File
        // bodies (snapshotted into memory).
        assert_eval_type_error("fetch('https://example.test/', { body: new Blob(['x']) })");
        assert_eval_true(
            "new Request('https://example.test/api', { method: 'POST', body: new Blob(['x']) }) instanceof Request",
        );
        assert_eval_true("new Response(new Blob(['x'])) instanceof Response");
    }

    // ── Request (WHATWG Fetch §5) ────────────────────────────────────────

    #[test]
    fn e2e_request_constructor_shape_and_defaults() {
        assert_eval_true("typeof Request === 'function' && Request.name === 'Request'");
        assert_eval_true("new Request('https://example.test/') instanceof Request");
        assert_eval_true(
            "Object.prototype.toString.call(new Request('https://example.test/')) === '[object Request]'",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/path?q=1'); q.method === 'GET' && q.url === 'https://example.test/path?q=1'",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/'); q.destination === '' && q.referrer === 'about:client' && q.referrerPolicy === ''",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/'); q.mode === 'cors' && q.credentials === 'same-origin' && q.cache === 'default' && q.redirect === 'follow'",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/'); q.integrity === '' && q.keepalive === false && q.signal === null && q.body === null && q.bodyUsed === false",
        );
    }

    #[test]
    fn e2e_request_constructs_from_url_and_rejects_relative_without_base() {
        assert_eval_true(
            "var u = new URL('https://example.test/a/../b'); var q = new Request(u); q.url === 'https://example.test/b'",
        );
        assert_eval_type_error("new Request('/relative')");
        assert_eval_type_error("new Request('not a url')");
    }

    #[test]
    fn e2e_request_init_method_headers_and_modes() {
        assert_eval_true(
            "var q = new Request('https://example.test/', { method: 'post', headers: { 'X-A': '1' } }); q.method === 'POST' && q.headers.get('x-a') === '1'",
        );
        assert_eval_true(
            "var h = new Headers({ A: '1' }); var q = new Request('https://example.test/', { headers: h }); q.headers instanceof Headers && q.headers === q.headers && q.headers.get('a') === '1'",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/', { mode: 'same-origin', credentials: 'include', cache: 'reload', redirect: 'manual', integrity: 'sha256-x', keepalive: true, referrer: '' }); q.mode === 'same-origin' && q.credentials === 'include' && q.cache === 'reload' && q.redirect === 'manual' && q.integrity === 'sha256-x' && q.keepalive === true && q.referrer === ''",
        );
        assert_eval_type_error("new Request('https://example.test/', { method: 'bad method' })");
        assert_eval_type_error("new Request('https://example.test/', { method: 'TRACE' })");
        assert_eval_type_error("new Request('https://example.test/', { mode: 'websocket' })");
    }

    #[test]
    fn e2e_request_body_types_supported_and_get_head_rejected() {
        assert_eval_true(
            "var q = new Request('https://example.test/', { method: 'POST', body: 'hi' }); q.headers.get('content-type') === 'text/plain;charset=UTF-8'",
        );
        assert_eval_true(
            "new Request('https://example.test/', { method: 'POST', body: new Blob(['hi'], { type: 'text/plain' }) }).headers.get('content-type') === 'text/plain'",
        );
        assert_eval_true(
            "new Request('https://example.test/', { method: 'POST', body: new Uint8Array([1,2,3]) }) instanceof Request",
        );
        assert_eval_true(
            "new Request('https://example.test/', { method: 'POST', body: new DataView(new ArrayBuffer(2)) }) instanceof Request",
        );
        assert_eval_type_error("new Request('https://example.test/', { body: 'x' })");
        assert_eval_type_error(
            "new Request('https://example.test/', { method: 'HEAD', body: 'x' })",
        );
        assert_eval_type_error(
            "new Request('https://example.test/', { method: 'POST', body: new FormData() })",
        );
    }

    #[test]
    fn e2e_request_body_methods_body_used_and_clone() {
        assert_eval_true(
            "var q = new Request('https://example.test/', { method: 'POST', body: 'hi' }); var p = q.text(); typeof p === 'object' && typeof p.then === 'function' && q.bodyUsed === true",
        );
        assert_eval_true_after_microtasks(
            "var requestJsonGot = null; var q = new Request('https://example.test/', { method: 'POST', body: '{\"a\":1}' }); q.json().then(function(v){ requestJsonGot = v; });",
            "requestJsonGot !== null && requestJsonGot.a === 1",
        );
        assert_eval_true_after_microtasks(
            "var requestFormGot = null; var q = new Request('https://example.test/', { method: 'POST', body: 'a=1&b=hello+world&a=2', headers: { 'Content-Type': 'application/x-www-form-urlencoded;charset=UTF-8' } }); q.formData().then(function(v){ requestFormGot = v; });",
            "requestFormGot instanceof FormData && requestFormGot.get('a') === '1' && requestFormGot.getAll('a').length === 2 && requestFormGot.get('b') === 'hello world'",
        );
        assert_eval_true(
            "var q = new Request('https://example.test/', { method: 'POST', body: 'x' }); var c = q.clone(); q.text(); c.bodyUsed === false && c.method === 'POST' && c.url === q.url",
        );
        assert_eval_type_error(
            "var q = new Request('https://example.test/', { method: 'POST', body: 'x' }); q.text(); q.clone()",
        );
        assert_eval_true_after_microtasks(
            "var requestReuseRejected = false; var q = new Request('https://example.test/', { method: 'POST', body: 'x' }); q.text(); q.text().then(function(){}, function(){ requestReuseRejected = true; });",
            "requestReuseRejected === true",
        );
        assert_eval_true_after_microtasks(
            "var requestFormReuseRejected = false; var q = new Request('https://example.test/', { method: 'POST', body: 'a=1', headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }); q.formData(); q.text().then(function(){}, function(){ requestFormReuseRejected = true; });",
            "requestFormReuseRejected === true && q.bodyUsed === true",
        );
        assert_eval_true_after_microtasks(
            "var requestMultipartRejected = false; var q = new Request('https://example.test/', { method: 'POST', body: '--x', headers: { 'Content-Type': 'multipart/form-data; boundary=x' } }); q.formData().then(function(){}, function(){ requestMultipartRejected = true; });",
            "requestMultipartRejected === true && q.bodyUsed === true",
        );
    }

    #[test]
    fn e2e_request_constructs_from_request_and_overrides_init() {
        assert_eval_true(
            "var a = new Request('https://example.test/a', { method: 'POST', body: 'x', headers: { A: '1' } }); var b = new Request(a); b.method === 'POST' && b.url === 'https://example.test/a' && b.headers.get('a') === '1'",
        );
        assert_eval_true(
            "var a = new Request('https://example.test/a', { method: 'POST', body: 'x', headers: { A: '1' } }); var b = new Request(a, { method: 'PUT', body: 'y', headers: { B: '2' } }); b.method === 'PUT' && b.headers.get('a') === null && b.headers.get('b') === '2'",
        );
        assert_eval_type_error(
            "var a = new Request('https://example.test/a', { method: 'POST', body: 'x' }); a.text(); new Request(a)",
        );
    }

    #[test]
    fn e2e_request_does_not_unlock_fetch_streams_or_cache() {
        assert_eval_type_error("fetch(new Request('https://example.test/'))");
        assert_eval_type_error("new ReadableStream({ start() {} })");
        assert_eval_type_error("new WritableStream({ write() {} })");
        assert_eval_true(
            "new Request('https://example.test/', { method: 'POST', body: 'x' }).body === null",
        );
        assert_eval_type_error("caches.open('x')");
    }

    // ── Event / CustomEvent (DOM §2) ───────────────────────────────────

    #[test]
    fn e2e_event_constructor_shape_and_defaults() {
        assert_eval_true("typeof Event === 'function' && Event.name === 'Event'");
        assert_eval_true("new Event('x') instanceof Event");
        assert_eval_true("Object.prototype.toString.call(new Event('x')) === '[object Event]'");
        // Type coercion of the type argument.
        assert_eval_true("new Event(123).type === '123'");
        // Default flags are all false.
        assert_eval_true(
            "var e = new Event('x'); \
             e.type === 'x' && \
             e.bubbles === false && \
             e.cancelable === false && \
             e.composed === false && \
             e.defaultPrevented === false && \
             e.isTrusted === false && \
             e.eventPhase === 0 && \
             e.target === null && \
             e.currentTarget === null && \
             e.srcElement === null && \
             typeof e.timeStamp === 'number'",
        );
    }

    #[test]
    fn e2e_event_constructor_requires_type_argument() {
        assert_eval_type_error("new Event()");
    }

    #[test]
    fn e2e_event_init_dict_coerces_flags() {
        assert_eval_true(
            "var e = new Event('x', { bubbles: 1, cancelable: 'y', composed: {} }); \
             e.bubbles === true && e.cancelable === true && e.composed === true",
        );
        assert_eval_true(
            "var e = new Event('x', { bubbles: 0, cancelable: '', composed: null }); \
             e.bubbles === false && e.cancelable === false && e.composed === false",
        );
        // Non-object, non-null/undefined init throws.
        assert_eval_type_error("new Event('x', 42)");
    }

    #[test]
    fn e2e_event_prevent_default_respects_cancelable() {
        assert_eval_true(
            "var e = new Event('x', { cancelable: true }); \
             e.preventDefault(); e.defaultPrevented === true",
        );
        assert_eval_true(
            "var e = new Event('x'); e.preventDefault(); e.defaultPrevented === false",
        );
    }

    #[test]
    fn e2e_event_stop_propagation_flags_are_observable_via_legacy_cancel_bubble() {
        assert_eval_true(
            "var e = new Event('x'); e.cancelBubble === false && \
             (e.stopPropagation(), e.cancelBubble === true)",
        );
        assert_eval_true("var e = new Event('x'); e.cancelBubble = true; e.cancelBubble === true");
        // Per spec, assigning false is a no-op (cannot un-stop propagation).
        assert_eval_true(
            "var e = new Event('x'); e.stopPropagation(); \
             e.cancelBubble = false; e.cancelBubble === true",
        );
    }

    #[test]
    fn e2e_event_return_value_legacy_mirrors_default_prevented() {
        assert_eval_true(
            "var e = new Event('x', { cancelable: true }); \
             e.returnValue === true && \
             (e.returnValue = false, e.defaultPrevented === true && e.returnValue === false)",
        );
        // Non-cancelable events cannot be flagged via returnValue either.
        assert_eval_true(
            "var e = new Event('x'); e.returnValue = false; \
             e.defaultPrevented === false && e.returnValue === true",
        );
    }

    #[test]
