    /// WebCodecs interface constructors (`VideoFrame`, `AudioData`, encoded
    /// chunks, encoders, decoders, `ImageDecoder`, image tracks) are exposed
    /// so feature detection succeeds, but construction fails closed because
    /// the engine has no media codecs, color-space conversion, demuxer, or
    /// event-loop integration to produce real frames or chunks.
    #[test]
    fn e2e_webcodecs_constructors_exist_but_fail_closed() {
        for name in [
            "VideoFrame",
            "AudioData",
            "EncodedVideoChunk",
            "EncodedAudioChunk",
            "VideoEncoder",
            "VideoDecoder",
            "AudioEncoder",
            "AudioDecoder",
            "ImageDecoder",
            "ImageTrack",
            "ImageTrackList",
        ] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }

        assert_eval_type_error(
            "new VideoEncoder({ output: function () {}, error: function () {} })",
        );
        assert_eval_type_error(
            "new VideoDecoder({ output: function () {}, error: function () {} })",
        );
        assert_eval_type_error(
            "new AudioEncoder({ output: function () {}, error: function () {} })",
        );
        assert_eval_type_error(
            "new AudioDecoder({ output: function () {}, error: function () {} })",
        );
        assert_eval_type_error(
            "new EncodedVideoChunk({ type: 'key', timestamp: 0, data: new Uint8Array(0) })",
        );
        assert_eval_type_error(
            "new EncodedAudioChunk({ type: 'key', timestamp: 0, data: new Uint8Array(0) })",
        );
    }

    /// WebGPU interface constructors (`GPU`, adapter/device/queue/buffer/
    /// texture/pipeline/bind-group/sampler/shader/compilation/error types,
    /// `GPUUncapturedErrorEvent`) are exposed so feature detection and
    /// `instanceof` checks succeed, but construction fails closed because
    /// the engine has no real GPU adapter, driver, command-submission queue,
    /// or async error scopes. Real instances are vended through
    /// `navigator.gpu`, which deliberately remains absent.
    #[test]
    fn e2e_webgpu_constructors_exist_but_fail_closed() {
        for name in [
            "GPU",
            "GPUAdapter",
            "GPUDevice",
            "GPUBuffer",
            "GPUTexture",
            "GPUTextureView",
            "GPUCommandEncoder",
            "GPUCommandBuffer",
            "GPUQueue",
            "GPURenderPipeline",
            "GPUComputePipeline",
            "GPUBindGroup",
            "GPUSampler",
            "GPUShaderModule",
            "GPUCompilationInfo",
            "GPUCompilationMessage",
            "GPUError",
            "GPUValidationError",
            "GPUOutOfMemoryError",
            "GPUInternalError",
            "GPUUncapturedErrorEvent",
        ] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }

        assert_eval_type_error("new GPUValidationError('bad shader')");
        assert_eval_type_error("new GPUOutOfMemoryError('oom')");
        assert_eval_type_error("new GPUInternalError('internal')");
        assert_eval_type_error("new GPUUncapturedErrorEvent('uncapturederror', { error: null })");
    }

    /// WebGL context interface constructors are exposed so page scripts can
    /// run `instanceof` checks against context objects, but construction
    /// fails closed because the engine has no `<canvas>` host element or GL
    /// driver to back a real rendering context.
    #[test]
    fn e2e_webgl_context_constructors_exist_but_fail_closed() {
        for name in ["WebGLRenderingContext", "WebGL2RenderingContext"] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }
    }

    /// WebXR interface constructors (`XRSystem`, sessions, frames, reference
    /// spaces, views, rigid transforms, WebGL layers, anchors, hit-test
    /// sources) are exposed so feature detection succeeds, but construction
    /// fails closed because the engine has no XR runtime, head-tracked frame
    /// loop, or host session lifetime. Real sessions are vended through
    /// `navigator.xr`, which deliberately remains absent.
    #[test]
    fn e2e_webxr_constructors_exist_but_fail_closed() {
        for name in [
            "XRSystem",
            "XRSession",
            "XRFrame",
            "XRReferenceSpace",
            "XRView",
            "XRRigidTransform",
            "XRWebGLLayer",
            "XRAnchor",
            "XRHitTestSource",
        ] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }

        assert_eval_type_error(
            "new XRRigidTransform({ x: 0, y: 0, z: 0, w: 1 }, { x: 0, y: 0, z: 0, w: 1 })",
        );
    }

    /// WebNN interface constructors (`ML`, `MLContext`, `MLGraph`,
    /// `MLGraphBuilder`, `MLOperand`) are exposed so feature detection
    /// succeeds, but construction fails closed because the engine has no
    /// ML accelerator backend or graph compiler. Real contexts are vended
    /// through `navigator.ml`, which deliberately remains absent.
    #[test]
    fn e2e_webnn_constructors_exist_but_fail_closed() {
        for name in ["ML", "MLContext", "MLGraph", "MLGraphBuilder", "MLOperand"] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }
    }

    /// Entry points that would vend fake codec, GPU, WebGL, XR or ML host
    /// objects remain absent. Real instances of the WebCodecs/WebGPU/WebGL/
    /// WebXR/WebNN interfaces are only reachable through `navigator.gpu`,
    /// `navigator.xr`, `navigator.ml`, `document` or canvas context creation
    /// — none of which the engine fakes. The interface constructors above
    /// only fail closed for feature detection and `instanceof` checks.
    /// (`HTMLCanvasElement`, `OffscreenCanvas` and `createImageBitmap` are
    /// covered by the canvas/imaging lane: they exist as constructors but
    /// also fail closed.)
    #[test]
    fn e2e_codec_graphics_host_entry_points_remain_absent() {
        assert_eval_true("typeof navigator === 'undefined'");
        assert_eval_true("typeof document === 'undefined'");
    }

    /// Entry points that would vend fake document/window/screen/media-query
    /// host objects remain absent; their constructors above only fail closed
    /// for feature detection.
    #[test]
    fn e2e_visual_host_entry_points_remain_absent() {
        for name in [
            "document",
            "window",
            "location",
            "history",
            "customElements",
            "frames",
            "top",
            "parent",
            "screen",
            "visualViewport",
            "matchMedia",
        ] {
            assert_eval_true(&format!("typeof {name} === 'undefined'"));
        }
    }

    /// Performance timeline subclasses that require a browser timeline,
    /// resource loader, rendering pipeline, navigation scheduler or
    /// task-attribution machinery to populate real entries are exposed as
    /// fail-closed constructors so feature detection succeeds but
    /// construction throws. `Performance`, `PerformanceEntry` and
    /// `PerformanceMeasure` constructors are also illegal per the spec.
    /// `PerformanceMark` IS a real constructor (see
    /// `e2e_performance_mark_constructor_works`).
    #[test]
    fn e2e_performance_timeline_constructors_exist_but_fail_closed() {
        for name in [
            "Performance",
            "PerformanceEntry",
            "PerformanceMeasure",
            "PerformanceResourceTiming",
            "PerformanceNavigationTiming",
            "PerformancePaintTiming",
            "PerformanceEventTiming",
            "PerformanceLongTaskTiming",
            "TaskAttributionTiming",
            "LargestContentfulPaint",
            "LayoutShift",
            "LayoutShiftAttribution",
            "VisibilityStateEntry",
        ] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
            assert_eval_type_error(&format!("new {name}()"));
        }
    }

    /// The `performance` global is installed and exposes a stable
    /// `timeOrigin` (Unix-epoch ms captured at install time), a monotonic
    /// `now()` (ms since `timeOrigin`), and the User Timing surface.
    #[test]
    fn e2e_performance_global_exists_with_real_shape() {
        assert_eval_true("typeof performance === 'object' && performance !== null");
        assert_eval_true("performance instanceof Performance");
        assert_eval_true(
            "typeof performance.now === 'function' && typeof performance.timeOrigin === 'number'",
        );
        assert_eval_true("typeof performance.mark === 'function'");
        assert_eval_true("typeof performance.measure === 'function'");
        assert_eval_true("typeof performance.clearMarks === 'function'");
        assert_eval_true("typeof performance.clearMeasures === 'function'");
        assert_eval_true("typeof performance.getEntries === 'function'");
        assert_eval_true("typeof performance.getEntriesByName === 'function'");
        assert_eval_true("typeof performance.getEntriesByType === 'function'");
    }

    /// `performance.timeOrigin` is captured at install time and never
    /// changes for the lifetime of the context.
    #[test]
    fn e2e_performance_time_origin_is_stable() {
        assert_eval_true(
            "const a = performance.timeOrigin; const b = performance.timeOrigin; a === b",
        );
        assert_eval_true("performance.timeOrigin > 0 && Number.isFinite(performance.timeOrigin)");
    }

    /// `performance.now()` is monotonic non-decreasing within a context.
    #[test]
    fn e2e_performance_now_is_monotonic() {
        assert_eval_true(
            "(function () {                 \
                let prev = performance.now();        \
                for (let i = 0; i < 1000; i++) {     \
                    const v = performance.now();     \
                    if (v < prev) return false;      \
                    prev = v;                        \
                }                                    \
                return true;                         \
            })()",
        );
    }

    /// `performance.mark` records a `PerformanceMark` with the spec shape;
    /// `performance.measure` records a `PerformanceMeasure` whose duration
    /// is derived from the named marks.
    #[test]
    fn e2e_performance_mark_and_measure_user_timing() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                const m = performance.mark('a');                         \
                if (!(m instanceof PerformanceMark)) return false;       \
                if (!(m instanceof PerformanceEntry)) return false;      \
                if (m.name !== 'a' || m.entryType !== 'mark') return false; \
                if (typeof m.startTime !== 'number') return false;       \
                if (m.duration !== 0) return false;                      \
                performance.mark('b');                                   \
                const ms = performance.measure('m', 'a', 'b');           \
                if (!(ms instanceof PerformanceMeasure)) return false;   \
                if (!(ms instanceof PerformanceEntry)) return false;     \
                if (ms.name !== 'm' || ms.entryType !== 'measure') return false; \
                if (ms.duration < 0) return false;                       \
                return true;                                             \
            })()",
        );
    }

    /// `performance.mark(name, { startTime, detail })` honors the options
    /// bag and `performance.getEntries*` filters by name and type.
    #[test]
    fn e2e_performance_mark_options_and_get_entries() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                const m = performance.mark('x', { startTime: 42, detail: { k: 1 } }); \
                if (m.startTime !== 42) return false;                    \
                if (!m.detail || m.detail.k !== 1) return false;         \
                performance.mark('y', { startTime: 10 });                \
                const all = performance.getEntries();                    \
                if (!Array.isArray(all) || all.length !== 2) return false; \
                if (all[0].name !== 'y' || all[1].name !== 'x') return false; \
                const byName = performance.getEntriesByName('x');        \
                if (byName.length !== 1 || byName[0].name !== 'x') return false; \
                const byType = performance.getEntriesByType('mark');     \
                if (byType.length !== 2) return false;                   \
                return true;                                             \
            })()",
        );
    }

    /// `clearMarks(name)` and `clearMeasures(name)` remove only the named
    /// entries; the no-arg form removes all of that type.
    #[test]
    fn e2e_performance_clear_marks_and_measures() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                performance.mark('a'); performance.mark('b'); performance.mark('a'); \
                performance.clearMarks('a');                             \
                if (performance.getEntriesByName('a').length !== 0) return false; \
                if (performance.getEntriesByName('b').length !== 1) return false; \
                performance.clearMarks();                                \
                if (performance.getEntries().length !== 0) return false; \
                performance.mark('s'); performance.mark('e');            \
                performance.measure('m1', 's', 'e');                     \
                performance.measure('m2', 's', 'e');                     \
                performance.clearMeasures('m1');                         \
                if (performance.getEntriesByType('measure').length !== 1) return false; \
                performance.clearMeasures();                             \
                if (performance.getEntriesByType('measure').length !== 0) return false; \
                return true;                                             \
            })()",
        );
    }

    /// `performance.measure` accepts an options bag with `start`/`end`/
    /// `duration` and rejects all three or unknown mark names.
    #[test]
    fn e2e_performance_measure_options_bag() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                const m = performance.measure('m', { start: 10, duration: 5 }); \
                if (m.startTime !== 10 || m.duration !== 5) return false; \
                const m2 = performance.measure('m2', { start: 1, end: 4 }); \
                if (m2.duration !== 3) return false;                     \
                return true;                                             \
            })()",
        );
        assert_eval_true(
            "(function () {                                              \
                try { performance.measure('x', { start: 1, end: 2, duration: 1 }); } \
                catch (e) { return e instanceof SyntaxError; }           \
                return false;                                            \
            })()",
        );
        assert_eval_true(
            "(function () {                                              \
                try { performance.measure('x', 'nope'); }                \
                catch (e) { return e instanceof SyntaxError; }           \
                return false;                                            \
            })()",
        );
    }

    /// `getEntriesByType` returns empty arrays for entry types that have
    /// no host integration in standalone Stator (no fake resource or
    /// navigation entries are fabricated).
    #[test]
    fn e2e_performance_unsupported_entry_types_are_empty() {
        for ty in ["resource", "navigation", "paint", "longtask", "event"] {
            assert_eval_true(&format!(
                "Array.isArray(performance.getEntriesByType('{ty}')) && performance.getEntriesByType('{ty}').length === 0"
            ));
        }
    }

    /// `PerformanceMark` is a callable constructor per spec; `Performance`,
    /// `PerformanceEntry` and `PerformanceMeasure` are illegal constructors.
    #[test]
    fn e2e_performance_mark_constructor_works() {
        assert_eval_true(
            "(function () {                                              \
                const m = new PerformanceMark('hello', { startTime: 7, detail: 42 }); \
                return m instanceof PerformanceMark                      \
                    && m instanceof PerformanceEntry                     \
                    && m.name === 'hello'                                \
                    && m.entryType === 'mark'                            \
                    && m.startTime === 7                                 \
                    && m.duration === 0                                  \
                    && m.detail === 42;                                  \
            })()",
        );
        assert_eval_type_error("new Performance()");
        assert_eval_type_error("new PerformanceEntry()");
        assert_eval_type_error("new PerformanceMeasure()");
    }

    /// `Performance.prototype.*` methods brand-check their receiver.
    #[test]
    fn e2e_performance_prototype_methods_require_branded_receiver() {
        for expr in [
            "Performance.prototype.now.call({})",
            "Performance.prototype.mark.call({}, 'x')",
            "Performance.prototype.measure.call({}, 'x')",
            "Performance.prototype.getEntries.call({})",
            "Object.getOwnPropertyDescriptor(Object.getPrototypeOf(performance), 'timeOrigin').get.call({})",
        ] {
            assert_eval_type_error(expr);
        }
    }

    /// Host-integrated performance surfaces remain absent or fail-closed:
    /// `PerformanceObserver` cannot be constructed, and the legacy
    /// `performance.timing` / `performance.navigation` / `performance.memory`
    /// extensions are not exposed.
    #[test]
    fn e2e_performance_host_integrations_stay_fail_closed() {
        assert_eval_type_error("new PerformanceObserver(function () {})");
        assert_eval_true("typeof performance.timing === 'undefined'");
        assert_eval_true("typeof performance.navigation === 'undefined'");
        assert_eval_true("typeof performance.memory === 'undefined'");
        assert_eval_true("typeof performance.onresourcetimingbufferfull === 'undefined'");
    }

    /// `performance.mark` and `new PerformanceMark` default `detail` to
    /// `null` (per User-Timing spec), not `undefined`. The detail value
    /// passed through `{ detail }` is preserved as-is.
    #[test]
    fn e2e_performance_mark_detail_defaults_to_null() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                const m1 = performance.mark('a');                        \
                if (m1.detail !== null) return false;                    \
                const m2 = performance.mark('b', { startTime: 1 });      \
                if (m2.detail !== null) return false;                    \
                const m3 = performance.mark('c', { detail: undefined }); \
                if (m3.detail !== null) return false;                    \
                const m4 = performance.mark('d', { detail: null });      \
                if (m4.detail !== null) return false;                    \
                const m5 = new PerformanceMark('e');                     \
                if (m5.detail !== null) return false;                    \
                const m6 = new PerformanceMark('f', { startTime: 0 });   \
                if (m6.detail !== null) return false;                    \
                return true;                                             \
            })()",
        );
    }

    /// `performance.measure` defaults `detail` to `null`, regardless of
    /// whether the options bag is omitted, an options bag without a
    /// `detail` key is passed, or the legacy `(name, startMark, endMark)`
    /// form is used.
    #[test]
    fn e2e_performance_measure_detail_defaults_to_null() {
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                performance.mark('s'); performance.mark('e');            \
                const a = performance.measure('a');                      \
                if (a.detail !== null) return false;                     \
                const b = performance.measure('b', 's', 'e');            \
                if (b.detail !== null) return false;                     \
                const c = performance.measure('c', { start: 0, end: 1 }); \
                if (c.detail !== null) return false;                     \
                const d = performance.measure('d', { start: 0, end: 1, detail: { k: 7 } }); \
                if (!d.detail || d.detail.k !== 7) return false;         \
                return true;                                             \
            })()",
        );
    }

    /// Observers that depend on a live DOM, layout pipeline, resource
    /// loader, or host event loop remain fail-closed: their constructors
    /// throw and `performance.getEntriesByType` returns empty arrays for
    /// host-integrated entry types (no fabricated records leak in).
    #[test]
    fn e2e_observers_remain_fail_closed_and_no_fake_entries() {
        for ctor in [
            "new MutationObserver(function () {})",
            "new IntersectionObserver(function () {})",
            "new ResizeObserver(function () {})",
            "new PerformanceObserver(function () {})",
            "new ReportingObserver(function () {})",
        ] {
            assert_eval_type_error(ctor);
        }
        // No host producer is wired, so getEntries must not contain
        // anything beyond the user-timing entries we explicitly created.
        assert_eval_true(
            "(function () {                                              \
                performance.clearMarks(); performance.clearMeasures();   \
                const all = performance.getEntries();                    \
                if (all.length !== 0) return false;                      \
                for (const ty of ['resource','navigation','paint',       \
                                  'longtask','event','layout-shift',     \
                                  'largest-contentful-paint',            \
                                  'first-input','element','visibility-state', \
                                  'taskattribution']) {                  \
                    const e = performance.getEntriesByType(ty);          \
                    if (!Array.isArray(e) || e.length !== 0) return false; \
                }                                                        \
                return true;                                             \
            })()",
        );
    }

    /// Browser self-reference globals (`window`, `self`, `frames`, `parent`,
    /// `top`, `screen`, `navigator`, `document`) are intentionally absent
    /// from the standalone engine — they are host-integrated and any built-in
    /// stub would either fake a missing window/document or shadow a real
    /// binding provided by an embedder (e.g. the DOM bridge in
    /// `stator_ffi`). The host installs `document` per context; the engine
    /// itself does not preinstall it.
    #[test]
    fn e2e_browser_self_reference_globals_are_absent() {
        assert_eval_true("typeof window === 'undefined'");
        assert_eval_true("typeof self === 'undefined'");
        assert_eval_true("typeof frames === 'undefined'");
        assert_eval_true("typeof parent === 'undefined'");
        assert_eval_true("typeof top === 'undefined'");
        assert_eval_true("typeof screen === 'undefined'");
        assert_eval_true("typeof navigator === 'undefined'");
        assert_eval_true("typeof document === 'undefined'");
    }

    #[test]
    fn e2e_event_constructor_is_real_and_constructs() {
        assert_eval_true("typeof Event === 'function' && Event.name === 'Event'");
        // Real construction succeeds and returns an Event instance.
        assert_eval_true("new Event('click') instanceof Event");
        // Calling without `new` also constructs (matches Stator's pattern
        // for fetch/URL/Headers/Request) and still returns an Event.
        assert_eval_true("Event('click') instanceof Event");
    }

    #[test]
    fn e2e_custom_event_constructor_is_real_and_constructs() {
        assert_eval_true("typeof CustomEvent === 'function' && CustomEvent.name === 'CustomEvent'");
        assert_eval_true("new CustomEvent('x', { detail: 1 }).detail === 1");
        assert_eval_true("CustomEvent('x') instanceof CustomEvent");
    }

    #[test]
    fn e2e_event_target_constructor_is_real_and_constructs() {
        assert_eval_true("typeof EventTarget === 'function' && EventTarget.name === 'EventTarget'");
        assert_eval_true("new EventTarget() instanceof EventTarget");
        assert_eval_true("EventTarget() instanceof EventTarget");
    }

    #[test]
    fn e2e_abort_controller_constructor_is_real_and_constructs() {
        assert_eval_true(
            "typeof AbortController === 'function' && AbortController.name === 'AbortController'",
        );
        assert_eval_type_error("AbortController()");
        assert_eval_true("new AbortController() instanceof AbortController");
    }

    #[test]
    fn e2e_abort_signal_constructor_exists_but_is_illegal() {
        assert_eval_true("typeof AbortSignal === 'function' && AbortSignal.name === 'AbortSignal'");
        assert_eval_type_error("AbortSignal()");
        assert_eval_type_error("new AbortSignal()");
        assert_eval_true("(new AbortController()).signal instanceof AbortSignal");
    }

    #[test]
    fn e2e_realtime_worker_messaging_constructors_exist_but_fail_closed() {
        for name in [
            "WebSocket",
            "EventSource",
            "WebTransport",
            "Worker",
            "SharedWorker",
            "ServiceWorker",
            "ServiceWorkerRegistration",
            "MessageChannel",
            "MessagePort",
            "BroadcastChannel",
        ] {
            assert_eval_true(&format!(
                "typeof {name} === 'function' && {name}.name === '{name}'"
            ));
            assert_eval_type_error(&format!("{name}()"));
        }

        assert_eval_type_error("new WebSocket('wss://example.test/socket')");
        assert_eval_type_error("new EventSource('/events')");
        assert_eval_type_error("new WebTransport('https://example.test/transport')");
        assert_eval_type_error("new Worker('/worker.js')");
        assert_eval_type_error("new SharedWorker('/shared-worker.js')");
        assert_eval_type_error("new ServiceWorker()");
        assert_eval_type_error("new ServiceWorkerRegistration()");
        assert_eval_type_error("new MessageChannel()");
        assert_eval_type_error("new MessagePort()");
        assert_eval_type_error("new BroadcastChannel('edge-stator')");

        // Construction with realistic option dictionaries is still rejected:
        // no fake module/credentials worker, named shared worker, or named
        // broadcast channel is created.
        assert_eval_type_error("new Worker('/worker.js', { type: 'module' })");
        assert_eval_type_error(
            "new Worker('/worker.js', { type: 'module', credentials: 'same-origin', name: 'w' })",
        );
        assert_eval_type_error("new SharedWorker('/shared-worker.js', 'name')");
        assert_eval_type_error(
            "new SharedWorker('/shared-worker.js', { name: 'n', type: 'module' })",
        );
        assert_eval_type_error("new BroadcastChannel('')");

        // `Reflect.construct` (with and without a `newTarget`) must not
        // bypass the fail-closed `__call__` check.
        for name in [
            "Worker",
            "SharedWorker",
            "ServiceWorker",
            "ServiceWorkerRegistration",
            "MessageChannel",
            "MessagePort",
            "BroadcastChannel",
        ] {
            assert_eval_type_error(&format!("Reflect.construct({name}, [])"));
        }

        // The fail-closed prototypes intentionally expose no messaging
        // methods or attribute event handlers — exposing fake ones would
        // mislead product code that does `typeof port.postMessage ===
        // 'function'` feature checks.
        for (ctor, member) in [
            ("Worker", "postMessage"),
            ("Worker", "terminate"),
            ("Worker", "onmessage"),
            ("Worker", "onmessageerror"),
            ("Worker", "onerror"),
            ("SharedWorker", "port"),
            ("SharedWorker", "onerror"),
            ("ServiceWorker", "postMessage"),
            ("ServiceWorker", "state"),
            ("ServiceWorker", "scriptURL"),
            ("ServiceWorker", "onstatechange"),
            ("ServiceWorkerRegistration", "active"),
            ("ServiceWorkerRegistration", "installing"),
            ("ServiceWorkerRegistration", "waiting"),
            ("ServiceWorkerRegistration", "scope"),
            ("ServiceWorkerRegistration", "update"),
            ("ServiceWorkerRegistration", "unregister"),
            ("MessageChannel", "port1"),
            ("MessageChannel", "port2"),
            ("MessagePort", "postMessage"),
            ("MessagePort", "start"),
            ("MessagePort", "close"),
            ("MessagePort", "onmessage"),
            ("MessagePort", "onmessageerror"),
            ("BroadcastChannel", "postMessage"),
            ("BroadcastChannel", "close"),
            ("BroadcastChannel", "name"),
            ("BroadcastChannel", "onmessage"),
            ("BroadcastChannel", "onmessageerror"),
            ("WebSocket", "readyState"),
            ("WebSocket", "send"),
            ("WebSocket", "close"),
            ("EventSource", "readyState"),
            ("EventSource", "close"),
            ("WebTransport", "ready"),
            ("WebTransport", "closed"),
            ("WebTransport", "datagrams"),
            ("WebTransport", "close"),
        ] {
            assert_eval_true(&format!(
                "!Object.prototype.hasOwnProperty.call({ctor}.prototype, '{member}')"
            ));
        }
    }

    /// No standalone `postMessage` / `onmessage` / `onmessageerror` global is
    /// installed. Exposing one would either fake cross-context message
    /// delivery (when no real worker/channel/window exists) or shadow a
    /// real binding an embedder might provide. The DOM `dispatchEvent`
    /// surfaces remain reachable only via real `EventTarget` instances.
    #[test]
    fn e2e_standalone_post_message_globals_are_absent() {
        assert_eval_true("typeof postMessage === 'undefined'");
        assert_eval_true("typeof onmessage === 'undefined'");
        assert_eval_true("typeof onmessageerror === 'undefined'");
        // `close` (as a Window-level method that ends the browsing context)
        // must not be installed either — there is no window to close.
        assert_eval_true("typeof close === 'undefined'");
    }

    /// `MessageEvent` instance state is per-instance and the `ports` getter
    /// returns a *fresh* array each call so script mutations cannot leak
    /// into a future read or affect another event.
    #[test]
    fn e2e_message_event_state_is_per_instance_and_ports_are_fresh() {
        assert_eval_true(
            "var a = new MessageEvent('m', { data: 1, origin: 'a', lastEventId: '1' }); \
             var b = new MessageEvent('m', { data: 2, origin: 'b', lastEventId: '2' }); \
             a.data === 1 && b.data === 2 && a.origin === 'a' && b.origin === 'b' && \
             a.lastEventId === '1' && b.lastEventId === '2'",
        );
        // `data` identity is preserved across repeated getter reads.
        assert_eval_true(
            "var d = { k: 1 }; var e = new MessageEvent('m', { data: d }); \
             e.data === d && e.data === e.data",
        );
        // Every `ports` read yields a distinct empty array, so mutating
        // one return value cannot poison subsequent reads.
        assert_eval_true(
            "var e = new MessageEvent('m'); \
             var p1 = e.ports; var p2 = e.ports; \
             Array.isArray(p1) && Array.isArray(p2) && p1 !== p2 && \
             p1.length === 0 && p2.length === 0",
        );
        assert_eval_true(
            "var e = new MessageEvent('m'); \
             e.ports.push('x'); e.ports.length === 0",
        );
        // `source` stays null regardless of how many times it is read.
        assert_eval_true("var e = new MessageEvent('m'); e.source === null && e.source === null");
        // Legacy `initMessageEvent` is intentionally not implemented — no
        // way to retroactively attach a fake source/port to an event.
        assert_eval_true("typeof MessageEvent.prototype.initMessageEvent === 'undefined'");
    }

