    #[test]
    fn e2e_intl_never_returns_fake_en_us_formatting() {
        // Constructing any Intl service must throw rather than yield a fake
        // formatter that hard-codes English/Latin defaults.
        assert_eval_type_error("new Intl.NumberFormat('en-US').format(1234567.89)");
        assert_eval_type_error("new Intl.DateTimeFormat('en-US').format(new Date(0))");
        assert_eval_type_error("new Intl.Collator('en-US').compare('a', 'b')");
        assert_eval_type_error("new Intl.ListFormat('en-US').format(['a', 'b'])");
        assert_eval_type_error("new Intl.PluralRules('en-US').select(1)");
        assert_eval_type_error("new Intl.RelativeTimeFormat('en-US').format(1, 'day')");
        assert_eval_type_error("new Intl.DisplayNames(['en-US'], { type: 'region' }).of('US')");
        assert_eval_type_error("new Intl.Segmenter('en-US').segment('hello')");
        assert_eval_type_error("new Intl.Locale('en-US').toString()");
    }

    #[test]
    fn e2e_locale_sensitive_builtins_use_locale_insensitive_fallbacks() {
        // Without ICU/Intl services, locale-sensitive built-ins outside `Intl`
        // must not pretend to support localized formatting, collation, or case
        // mapping. They keep the existing spec-allowed locale-insensitive
        // fallbacks instead.
        assert_eval_true("(1234567).toLocaleString('en-US', { useGrouping: true }) === '1234567'");
        assert_eval_true(
            "(1234567.89).toLocaleString('en-US', { useGrouping: true }) === '1234567.89'",
        );
        assert_eval_true(
            "var d = new Date(0); \
             d.toLocaleString('en-US', { timeZone: 'UTC' }) === d.toString() && \
             d.toLocaleDateString('en-US', { timeZone: 'UTC' }) === d.toDateString() && \
             d.toLocaleTimeString('en-US', { timeZone: 'UTC' }) === d.toTimeString()",
        );
        assert_eval_true(
            "'I'.toLocaleLowerCase('tr') === 'i' && \
             'i'.toLocaleUpperCase('tr') === 'I'",
        );
        assert_eval_true("'2'.localeCompare('10', undefined, { numeric: true }) > 0");
        assert_eval_true("'a'.localeCompare('A', undefined, { sensitivity: 'base' }) > 0");
        assert_eval_true(
            "[1234567, 'I'].toLocaleString('en-US', { useGrouping: true }) === '1234567,I'",
        );
    }

    /// Verify that the `Math` object has the expected properties.
    #[test]
    fn test_math_object_properties() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let math = globals.get("Math").unwrap();
        if let JsValue::PlainObject(map) = math {
            let map = map.borrow();
            assert!(map.contains_key("PI"));
            assert!(map.contains_key("E"));
            assert!(map.contains_key("floor"));
            assert!(map.contains_key("ceil"));
            assert!(map.contains_key("round"));
            assert!(map.contains_key("abs"));
            assert!(map.contains_key("sqrt"));
            assert!(map.contains_key("max"));
            assert!(map.contains_key("min"));
            assert!(map.contains_key("random"));
        } else {
            panic!("Math should be a PlainObject");
        }
    }

    /// Verify Math.PI value.
    #[test]
    fn test_math_pi_value() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let math = globals.get("Math").unwrap();
        if let JsValue::PlainObject(map) = math {
            let pi = map.borrow().get("PI").cloned().unwrap();
            if let JsValue::HeapNumber(n) = pi {
                assert!((n - std::f64::consts::PI).abs() < 1e-15);
            } else {
                panic!("PI should be a HeapNumber");
            }
        } else {
            panic!("Math should be a PlainObject");
        }
    }

    /// Call Math.floor via the built-in function object wrapper.
    #[test]
    fn test_math_floor_native() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let math = globals.get("Math").unwrap();
        if let JsValue::PlainObject(map) = math {
            let floor = map.borrow().get("floor").cloned().unwrap();
            // Math.floor is now a PlainObject with __call__, .name, .length
            if let JsValue::PlainObject(fn_obj) = &floor {
                let call_fn = fn_obj.borrow().get("__call__").cloned().unwrap();
                if let JsValue::NativeFunction(f) = call_fn {
                    let result = f(vec![JsValue::HeapNumber(1.7)]).unwrap();
                    assert_eq!(result, JsValue::Smi(1));
                } else {
                    panic!("__call__ should be a NativeFunction");
                }
                // Verify .name and .length
                let name = fn_obj.borrow().get("name").cloned().unwrap();
                assert_eq!(name, JsValue::String("floor".into()));
                let length = fn_obj.borrow().get("length").cloned().unwrap();
                assert_eq!(length, JsValue::Smi(1));
            } else {
                panic!("floor should be a PlainObject (builtin_fn)");
            }
        }
    }

    /// Call parseInt via the built-in function object wrapper.
    #[test]
    fn test_parse_int_builtin_function() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let parse_int = globals.get("parseInt").unwrap();
        let result = call_builtin_function(parse_int, vec![JsValue::String("42".into())]);
        assert_eq!(result, JsValue::Smi(42));
        assert_builtin_metadata(parse_int, "parseInt", 2);
    }

    /// Call isNaN via the built-in function object wrapper.
    #[test]
    fn test_is_nan_builtin_function() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let is_nan = globals.get("isNaN").unwrap();
        let result = call_builtin_function(is_nan, vec![JsValue::HeapNumber(f64::NAN)]);
        assert_eq!(result, JsValue::Boolean(true));

        let result = call_builtin_function(is_nan, vec![JsValue::Smi(42)]);
        assert_eq!(result, JsValue::Boolean(false));
        assert_builtin_metadata(is_nan, "isNaN", 1);
    }

    /// Call console.log via the built-in function object wrapper.
    #[test]
    fn test_console_log_builtin_function() {
        let mut globals = HashMap::new();
        install_globals(&mut globals);
        let console = globals.get("console").unwrap();
        let JsValue::PlainObject(map) = console else {
            panic!("console should be a PlainObject");
        };
        let log = map.borrow().get("log").cloned().unwrap();
        let result = call_builtin_function(&log, vec![JsValue::String("hello".into())]);
        assert_eq!(result, JsValue::Undefined);
        assert_builtin_metadata(&log, "log", 0);
    }

    // ── End-to-end tests: parse → compile → interpret ──────────────────────
    //
    // These tests exercise the full pipeline using `global_eval` which now
    // automatically gets globals installed via `InterpreterFrame::new`.

    use crate::builtins::global::global_eval;

