        let obj = JsonValue::Object(Rc::new(RefCell::new(vec![(
            "x".to_string(),
            JsonValue::Number(1.0),
        )])));
        let s = json_stringify(&obj, None, Some(&JsonSpace::Count(2)), None)
            .unwrap()
            .unwrap();
