    #[test]
    fn e2e_queue_microtask_exists() {
        assert_eval_true("typeof queueMicrotask === 'function'");
    }

    #[test]
    fn e2e_queue_microtask_runs_callback() {
        let result =
            global_eval("var order = []; queueMicrotask(function () { order.push('microtask'); }); order.length")
                .unwrap();
        assert_eq!(result, JsValue::Smi(0));
        drain_microtasks();
        assert_eq!(
            global_eval("order[0]").unwrap(),
            JsValue::String("microtask".into())
        );
    }

    #[test]
    fn e2e_queue_microtask_returns_undefined() {
        let result = global_eval("queueMicrotask(function () {})").unwrap();
        assert_eq!(result, JsValue::Undefined);
    }

    #[test]
    fn e2e_queue_microtask_accepts_arrow_function() {
        let result =
            global_eval("var value = 0; queueMicrotask(() => { value = 3; }); value").unwrap();
        assert_eq!(result, JsValue::Smi(0));
        drain_microtasks();
        assert_eq!(global_eval("value").unwrap(), JsValue::Smi(3));
    }

    #[test]
    fn e2e_queue_microtask_errors_do_not_throw_synchronously() {
        assert_eval_true(
            "var caught = false; try { queueMicrotask(function () { throw new Error('boom'); }); } catch (e) { caught = true; } caught === false",
        );
        drain_microtasks();
    }

    #[test]
    fn e2e_queue_microtask_errors_do_not_block_following_microtasks() {
        global_eval(
            "var order = []; \
             queueMicrotask(function () { order.push('first'); throw new Error('boom'); }); \
             queueMicrotask(function () { order.push('second'); });",
        )
        .unwrap();
        drain_microtasks();
        assert_eval_true("order.join(',') === 'first,second'");
    }

    #[test]
    fn e2e_queue_microtask_uses_fifo_order_with_promises() {
        global_eval(
            "var order = [];
             queueMicrotask(function () { order.push('queue-1'); });
             Promise.resolve().then(function () { order.push('promise'); });
             queueMicrotask(function () { order.push('queue-2'); });",
        )
        .unwrap();
        drain_microtasks();
        assert_eval_true("order.join(',') === 'queue-1,promise,queue-2'");
    }

    #[test]
    fn e2e_queue_microtask_shares_queue_with_promises_enqueued_inside_callback() {
        global_eval(
            "var order = []; \
             queueMicrotask(function () { \
                 order.push('queue'); \
                 Promise.resolve().then(function () { order.push('promise-inside'); }); \
             }); \
             Promise.resolve().then(function () { order.push('promise-before'); });",
        )
        .unwrap();
        drain_microtasks();
        assert_eval_true("order.join(',') === 'queue,promise-before,promise-inside'");
    }

