    #[test]
    fn test_date_get_utc_date() {
        let result = global_eval("new Date(1704067200000).getUTCDate()").unwrap();
        assert_eq!(result, JsValue::Smi(1));
    }

    /// `new Date(...)` UTC hours accessor.
