    fn test_object_keys_skips_symbol_keys() {
        let result = global_eval(
            "var s = Symbol('x'); \
             var o = { visible: 1 }; \
             o[s] = 2; \
             Object.keys(o).join(',')",
        )
        .unwrap();
        assert_eq!(result, JsValue::String("visible".into()));
    }

