    /// Spread with custom Symbol.iterator.
    #[test]
    fn e2e_spread_custom_iterator() {
        let r = global_eval(
            r#"
            var obj = {};
            obj[Symbol.iterator] = function() {
                var i = 0;
                return {
                    next: function() {
                        i++;
                        if (i <= 3) return { value: i, done: false };
                        return { done: true };
                    }
                };
            };
            var a = [...obj];
            a.join(',')
            "#,
        )
        .unwrap();
        assert_eq!(r, JsValue::String("1,2,3".into()));
    }

